//! Raw FFI bindings to the OpenZen C API.
//!
//! These types and function declarations are generated by hand from the
//! OpenZen headers (`OpenZenCAPI.h`, `ZenTypes.h`) at commit
//! `dd8d9269ccbbb5a3582ac4ecb622ae829f67aee7`.
//!
//! The companion `build.rs` clones and builds OpenZen from source so the
//! library is always available — no runtime `libloading` needed.

#![allow(non_camel_case_types, non_snake_case, non_upper_case_globals, dead_code)]

use std::os::raw::c_char;

// ---------------------------------------------------------------------------
// Handle types (C: struct { uintptr_t handle; })
// ---------------------------------------------------------------------------

#[repr(C)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct ZenClientHandle_t {
    pub handle: usize,
}

#[repr(C)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct ZenSensorHandle_t {
    pub handle: usize,
}

#[repr(C)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct ZenComponentHandle_t {
    pub handle: usize,
}

